const ServiceSession = () => (
  <ServiceSessionContainer>
    <SectionTitle className='universal-fs-h8 universal-font-bold'>
      What is a <span style={{ color: "#5485EE" }}>Design Session?</span>
    </SectionTitle>
    <ServiceSessionWrapper>
      {sessionData.map((session) => (
        <SessionItem key={session.id}>
          <SessionIcon>
            {session.svg}
          </SessionIcon>
          <SessionLabel>{session.label}</SessionLabel>
        </SessionItem>
      ))}
    </ServiceSessionWrapper>
  </ServiceSessionContainer>
);

const ServiceSessionWrapper = styled.div`
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 70px;
  margin: 0;
  justify-items: center;
  align-items: center;

  @media (max-width: 768px) {
    gap: 32px;
    grid-template-columns: repeat(2, 1fr);
    grid-template-rows: repeat(2, 1fr);
    width: 100%;
    padding: 0 8px;
  }

  @media (max-width: 480px) {
    grid-template-columns: repeat(2, 1fr);
    grid-template-rows: none;
    gap: 20px;
    padding: 0 4px;
  }
`;

const SessionItem = styled.div`
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-start;
  width: 100%;
  max-width: 250px;
  margin: 0 auto;
  
  @media (max-width: 768px) {
    max-width: 180px;
  }
  @media (max-width: 480px) {
    max-width: 100%;
    width: 100%;
  }
`;

const SessionIcon = styled.div`
  width: 250px;
  height: 170px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 10px;

  @media (max-width: 768px) {
    width: 140px;
    height: 90px;
    margin-bottom: 8px;
  }
  @media (max-width: 480px) {
    width: 100px;
    height: 60px;
    margin-bottom: 6px;
  }
`;

const SessionLabel = styled.div`
  font-size: var(--universal-fs-h3);
  color: #222;
  font-weight: 500;
  text-align: center;
  margin-top: 20px;
  word-break: break-word;

  @media (max-width: 768px) {
    font-size: var(--universal-fs-h4);
    margin-top: 12px;
  }
  @media (max-width: 480px) {
    font-size: var(--universal-fs-h5);
    margin-top: 8px;
  }
`;

