const Services = () => {
  const navigate = useNavigate();
  const [isConsultationOpen, setIsConsultationOpen] = useState(false);

  const handleCardClick = (title) => {
    if (title === "After-Sales Support") {
      navigate("/support");
    } else {
      setIsConsultationOpen(true);
    }
  };

  return (
    <ServicesContainer>
      <ContentWrapper>
        <SectionHeader>
          <SectionTitle className='universal-fs-h8 universal-font-bold'>
            Your <span style={{ color: "#5485EE" }}>Complete Destination</span> for <span style={{ color: "#559944" }}>Interior Excellence</span>
          </SectionTitle>
          <SectionDescription className='universal-fs-h3 universal-font-medium'>
            From full-scale interiors to modular makeovers, we handle it all — for your home or office. With a wide furniture, we’re your trusted partner from concept to completion.
          </SectionDescription>
          {/* <KnowMoreButton>Know More</KnowMoreButton> */}
        </SectionHeader>

        <ServicesGrid $cardCount={serviceData.length}>
          {serviceData.map((service, index) => (
            <ServiceCard
              key={index}
              image={service.image}
              title={service.title}
              description={service.description}
              fill={service.fill}
              onClick={() => handleCardClick(service.title)}
            />
          ))}
        </ServicesGrid>

        <ServiceSession />
      </ContentWrapper>

      <Modal open={isConsultationOpen} onClose={() => setIsConsultationOpen(false)}>
        <CloseButton onClick={() => setIsConsultationOpen(false)} className="universal-fs-h8 universal-font">&times;</CloseButton>
        <ConsultationFormContent onSuccess={() => setIsConsultationOpen(false)} />
      </Modal>
    </ServicesContainer>
  );
};

export default Services;



